// Extract and normalise burn event payload from PARAMANT relay
const body = $input.item.json.body || $input.item.json;

const event = {
  hash:           body.hash       || body.blob_hash  || 'unknown',
  sector:         body.sector     || 'unknown',
  device_id:      body.device_id  || body.device     || 'unknown',
  bytes:          body.bytes      || body.size        || 0,
  timestamp:      body.ts         || new Date().toISOString(),
  api_key_prefix: (body.api_key   || '').slice(0, 8) + '...',
  event_type:     body.event      || (body.burned ? 'burn' : 'view'),
};

// Flag anomalies
event.flagged = event.bytes === 0 || event.event_type !== 'burn';

console.log('[PARAMANT]', event.event_type, event.sector, event.hash.slice(0,16), event.bytes + 'B');

return { json: event };

// Build structured audit log entry for anomalous burns
const e = $input.item.json;
const entry = {
  timestamp:  e.timestamp,
  event:      e.event_type,
  sector:     e.sector,
  hash:       e.hash,
  bytes:      e.bytes,
  device_id:  e.device_id,
  api_key:    e.api_key_prefix,
  flagged:    true,
  reason:     e.bytes === 0 ? 'zero-byte blob' : 'non-burn event',
};

console.warn('[PARAMANT ALERT] Anomaly detected:', JSON.stringify(entry));

// TODO: Connect Claude AI credential to this node for intelligent analysis
// Add Anthropic Chat Model node and chain it here

return { json: entry };

// Clean burn — log silently
const e = $input.item.json;
console.log('[PARAMANT] clean burn:', e.sector, e.hash.slice(0,16), e.bytes + 'B', e.device_id);
return { json: { ok: true, sector: e.sector, hash: e.hash } };
